  1→import { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
  2→import { supabase } from '@/integrations/supabase/client';
  3→import type { TrackType } from '@/data/trackConfig';
  4→
  5→interface Team {
  6→  id: string;
  7→  name: string;
  8→  event_id: string | null;
  9→  invite_code: string;
 10→  track: TrackType | null;
 11→}
 12→
 13→interface TeamAuthContextType {
 14→  team: Team | null;
 15→  loading: boolean;
 16→  isAuthenticated: boolean;
 17→  createTeam: (teamName: string, password: string, memberNames?: string[]) => Promise<{ error: string | null; team: Team | null }>;
 18→  loginTeam: (teamName: string, password: string) => Promise<{ error: string | null; team: Team | null }>;
 19→  logout: () => void;
 20→  setTrack: (track: TrackType) => Promise<void>;
 21→}
 22→
 23→const TeamAuthContext = createContext<TeamAuthContextType | undefined>(undefined);
 24→
 25→const TEAM_SESSION_KEY = 'habitat_team_session';
 26→
 27→async function hashPassword(password: string): Promise<string> {
 28→  const encoder = new TextEncoder();
 29→  const data = encoder.encode(password);
 30→  const hash = await crypto.subtle.digest('SHA-256', data);
 31→  return Array.from(new Uint8Array(hash))
 32→    .map(b => b.toString(16).padStart(2, '0'))
 33→    .join('');
 34→}
 35→
 36→function generateInviteCode(): string {
 37→  return Math.random().toString(36).substring(2, 8).toUpperCase();
 38→}
 39→
 40→export function TeamAuthProvider({ children }: { children: ReactNode }) {
 41→  const [team, setTeam] = useState<Team | null>(null);
 42→  const [loading, setLoading] = useState(true);
 43→
 44→  useEffect(() => {
 45→    const stored = sessionStorage.getItem(TEAM_SESSION_KEY);
 46→    if (stored) {
 47→      try {
 48→        const parsed = JSON.parse(stored);
 49→        setTeam(parsed);
 50→      } catch {
 51→        sessionStorage.removeItem(TEAM_SESSION_KEY);
 52→      }
 53→    }
 54→    setLoading(false);
 55→  }, []);
 56→
 57→  useEffect(() => {
 58→    if (team) {
 59→      sessionStorage.setItem(TEAM_SESSION_KEY, JSON.stringify(team));
 60→    } else {
 61→      sessionStorage.removeItem(TEAM_SESSION_KEY);
 62→    }
 63→  }, [team]);
 64→
 65→  const createTeam = useCallback(async (
 66→    teamName: string, 
 67→    password: string,
 68→    memberNames?: string[]
 69→  ): Promise<{ error: string | null; team: Team | null }> => {
 70→    try {
 71→      const { data: existing } = await supabase
 72→        .from('teams')
 73→        .select('id')
 74→        .eq('name', teamName)
 75→        .maybeSingle();
 76→
 77→      if (existing) {
 78→        return { error: 'Team name already taken', team: null };
 79→      }
 80→
 81→      const passwordHash = await hashPassword(password);
 82→      const inviteCode = generateInviteCode();
 83→
 84→      const { data, error } = await supabase
 85→        .from('teams')
 86→        .insert({
 87→          name: teamName,
 88→          password_hash: passwordHash,
 89→          invite_code: inviteCode,
 90→        })
 91→        .select()
 92→        .single();
 93→
 94→      if (error) {
 95→        console.error('Create team error:', error);
 96→        return { error: 'Failed to create team', team: null };
 97→      }
 98→
 99→      if (memberNames && memberNames.length > 0) {
100→        const memberInserts = memberNames.map(name => ({
101→          team_id: data.id,
102→          name: name.trim(),
103→        }));
104→
105→        const { error: memberError } = await supabase
106→          .from('team_member_names')
107→          .insert(memberInserts);
108→
109→        if (memberError) {
110→          console.error('Error saving team members:', memberError);
111→        }
112→      }
113→
114→      const newTeam: Team = {
115→        id: data.id,
116→        name: data.name,
117→        event_id: data.event_id,
118→        invite_code: data.invite_code,
119→        track: data.track as TrackType | null,
120→      };
121→
122→      setTeam(newTeam);
123→      return { error: null, team: newTeam };
124→    } catch (err) {
125→      console.error('Create team error:', err);
126→      return { error: 'An unexpected error occurred', team: null };
127→    }
128→  }, []);
129→
130→  const loginTeam = useCallback(async (
131→    teamName: string, 
132→    password: string
133→  ): Promise<{ error: string | null; team: Team | null }> => {
134→    try {
135→      const passwordHash = await hashPassword(password);
136→
137→      const { data, error } = await supabase
138→        .from('teams')
139→        .select('id, name, event_id, invite_code, password_hash, track')
140→        .eq('name', teamName)
141→        .maybeSingle();
142→
143→      if (error || !data) {
144→        return { error: 'Team not found', team: null };
145→      }
146→
147→      if (data.password_hash !== passwordHash) {
148→        return { error: 'Incorrect password', team: null };
149→      }
150→
151→      const loggedInTeam: Team = {
152→        id: data.id,
153→        name: data.name,
154→        event_id: data.event_id,
155→        invite_code: data.invite_code,
156→        track: data.track as TrackType | null,
157→      };
158→
159→      setTeam(loggedInTeam);
160→      return { error: null, team: loggedInTeam };
161→    } catch (err) {
162→      console.error('Login error:', err);
163→      return { error: 'An unexpected error occurred', team: null };
164→    }
165→  }, []);
166→
167→  const logout = useCallback(() => {
168→    setTeam(null);
169→    sessionStorage.removeItem(TEAM_SESSION_KEY);
170→  }, []);
171→
172→  const setTrackFn = useCallback(async (track: TrackType) => {
173→    if (!team) throw new Error('No team logged in');
174→    
175→    const { error } = await supabase
176→      .from('teams')
177→      .update({ track })
178→      .eq('id', team.id);
179→
180→    if (error) throw error;
181→
182→    setTeam(prev => prev ? { ...prev, track } : null);
183→  }, [team]);
184→
185→  return (
186→    <TeamAuthContext.Provider 
187→      value={{ 
188→        team, 
189→        loading, 
190→        isAuthenticated: !!team,
191→        createTeam, 
192→        loginTeam, 
193→        logout,
194→        setTrack: setTrackFn,
195→      }}
196→    >
197→      {children}
198→    </TeamAuthContext.Provider>
199→  );
200→}
201→
202→export function useTeamAuth() {
203→  const context = useContext(TeamAuthContext);
204→  if (context === undefined) {
205→    throw new Error('useTeamAuth must be used within a TeamAuthProvider');
206→  }
207→  return context;
208→}
