178→export async function pauseTimer() {
179→  const { error } = await supabase
180→    .from('sprint_timer')
181→    .update({
182→      status: 'paused',
183→      paused_at: new Date().toISOString(),
184→    })
185→    .eq('id', TIMER_ID);
186→  
187→  if (error) throw error;
188→}
189→
190→export async function resumeTimer() {
191→  // First, get current state to calculate elapsed time
192→  const { data, error: fetchError } = await supabase
193→    .from('sprint_timer')
194→    .select('*')
195→    .eq('id', TIMER_ID)
196→    .maybeSingle();
197→  
198→  if (fetchError) throw fetchError;
199→  if (!data) throw new Error('Timer not found');
200→  
201→  let newElapsedBeforePause = data.elapsed_before_pause;
202→  
203→  if (data.started_at && data.paused_at) {
204→    const startedAt = new Date(data.started_at).getTime();
205→    const pausedAt = new Date(data.paused_at).getTime();
206→    newElapsedBeforePause += Math.floor((pausedAt - startedAt) / 1000);
207→  }
208→  
209→  const { error } = await supabase
210→    .from('sprint_timer')
211→    .update({
212→      status: 'running',
213→      started_at: new Date().toISOString(),
214→      paused_at: null,
215→      elapsed_before_pause: newElapsedBeforePause,
216→    })
217→    .eq('id', TIMER_ID);
218→  
219→  if (error) throw error;
220→}
